.loader {color: var(--loader-color, #4f46e5);
  --loader-secondary-color: #a5b4fc;
  --loader-bg: #ffffff;
   width: 80px;
   height: 40px;
   border-radius: 100px 100px 0 0;
   background: linear-gradient(0deg, #0000,currentColor,#0000) 70% 30%, linear-gradient(90deg,#0000,currentColor,#0000) 72% 32%, linear-gradient(0deg, #0000,currentColor,#0000) 26% 42%, linear-gradient(90deg,#0000,currentColor,#0000) 23% 44%, linear-gradient(0deg, #0000,currentColor,#0000) 51% 54%, linear-gradient(90deg,#0000,currentColor,#0000) 51% 53% var(--loader-secondary-color, #a5b4fc);
   background-size: 2px 10px,10px 2px;
   background-repeat: no-repeat;
   position: relative;
   overflow: hidden;
}
.loader:before, .loader:after  {
  content: "";
   position: absolute;
   inset: 100% auto auto 20px;
   height: 3px;
   width: 20px;
   background: linear-gradient(90deg,#0000,currentColor);
   transform-origin: right;
   transform: rotate(-20deg) translate(-20px);
   animation: l6 2s infinite;
}
.loader:after  {
  inset: 100% auto auto -5px;
   animation-delay: .75s;
}
@keyframes l6  {
  100% {transform: rotate(-20deg) translate(120px)}
}
